DO $$
DECLARE
  v_dealership_id uuid;
  v_module_id uuid := gen_random_uuid();
BEGIN
  -- Find the dealership
  SELECT id INTO v_dealership_id FROM public.dealerships WHERE name ILIKE '%lakeshore%' LIMIT 1;

  IF v_dealership_id IS NULL THEN
    INSERT INTO public.dealerships (id, name, slug) VALUES (gen_random_uuid(), 'My Lakeshore Subaru', 'my-lakeshore-subaru') RETURNING id INTO v_dealership_id;
  END IF;

  -- Module
  INSERT INTO public.dealership_modules (id, dealership_id, title, description, icon, sort_order, estimated_time, is_active)
  VALUES (v_module_id, v_dealership_id,
    'Handling Objections: The C.R.I.C. Method',
    'Every objection is a buying sign. Learn to categorize objections as Budget, Decision, or Deal — then master the C.R.I.C. framework (Clarify, Rephrase, Isolate, Close) to turn no into yes.',
    'MessageSquare', 12, '15-20 min', true);

  -- Section 1
  INSERT INTO public.dealership_module_sections (module_id, title, content_type, content_html, sort_order)
  VALUES (v_module_id, 'Why Objections Are Buying Signs', 'text', '<h2 class="text-xl font-bold mb-4 text-primary">Every ''No'' Is Actually a ''Tell Me More''</h2><p class="mb-4 leading-relaxed">Most salespeople hear an objection and feel defeated. Top performers hear an objection and get <strong>excited</strong> — because an objection means the customer is still engaged. They haven''t left. They''re asking you to help them get to "yes."</p><div class="bg-primary/5 border border-primary/20 rounded-lg p-4 text-center mb-4"><p class="font-bold text-primary text-lg">Objections are buying signs — they''re a customer''s request for more information.</p></div><p class="mb-4 leading-relaxed">A customer who truly doesn''t care just walks away. A customer who objects is telling you they''re <em>interested but something is in the way</em>.</p><h3 class="text-lg font-semibold mb-3 mt-6">The Three Categories</h3><p class="mb-4 leading-relaxed">Every objection fits into one of three categories:</p><div class="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6"><div class="bg-blue-50 dark:bg-blue-950/30 border border-blue-200 dark:border-blue-800 rounded-lg p-4 text-center"><p class="text-2xl font-bold text-blue-600 mb-1">BUDGET</p><p class="text-sm">"It''s too much money"</p><p class="text-sm">"We can''t afford it"</p></div><div class="bg-green-50 dark:bg-green-950/30 border border-green-200 dark:border-green-800 rounded-lg p-4 text-center"><p class="text-2xl font-bold text-green-600 mb-1">DECISION</p><p class="text-sm">"We want to think about it"</p><p class="text-sm">"I need to check with my spouse"</p></div><div class="bg-orange-50 dark:bg-orange-950/30 border border-orange-200 dark:border-orange-800 rounded-lg p-4 text-center"><p class="text-2xl font-bold text-orange-600 mb-1">DEAL</p><p class="text-sm">"We want to shop around"</p><p class="text-sm">"We want to compare prices"</p></div></div><div class="bg-amber-50 dark:bg-amber-950/30 border border-amber-300 dark:border-amber-700 rounded-lg p-4 mb-6"><p class="font-semibold text-amber-900 dark:text-amber-200">🧠 Check Yourself: A customer says ''I need to run this by my wife first.'' Which category?</p><p class="text-sm text-muted-foreground mt-2">Answer: Decision. They want help feeling confident in their choice.</p></div>', 1);

  -- Section 2
  INSERT INTO public.dealership_module_sections (module_id, title, content_type, content_html, sort_order)
  VALUES (v_module_id, 'Speed Kills — Why Slowing Down Closes More Deals', 'text', '<h2 class="text-xl font-bold mb-4 text-primary">The Data Doesn''t Lie</h2><p class="mb-4 leading-relaxed">One of the most damaging mistakes is rushing into price. The customer''s buying process requires <strong>time</strong>.</p><div class="space-y-3 mb-6"><div class="flex items-center gap-4 bg-red-50 dark:bg-red-950/30 rounded-lg p-4"><span class="text-3xl font-bold text-red-600 min-w-[60px]">6%</span><p>close rate at <strong>60 minutes or less</strong></p></div><div class="flex items-center gap-4 bg-amber-50 dark:bg-amber-950/30 rounded-lg p-4"><span class="text-3xl font-bold text-amber-600 min-w-[60px]">31%</span><p>close rate at <strong>more than 72 minutes</strong></p></div><div class="flex items-center gap-4 bg-green-50 dark:bg-green-950/30 rounded-lg p-4"><span class="text-3xl font-bold text-green-600 min-w-[60px]">57%</span><p>close rate at <strong>more than 100 minutes</strong></p></div></div><p class="mb-4 leading-relaxed">That''s <strong>almost 10x more closes</strong> when you invest time vs rush through.</p><h3 class="text-lg font-semibold mb-3 mt-6">Rules During Objections</h3><ul class="list-disc pl-6 mb-4 space-y-2"><li><strong>Remain professional.</strong> No defensiveness or sarcasm.</li><li><strong>Let the customer finish speaking.</strong> Don''t interrupt.</li><li><strong>Affirm their objection</strong> by echoing what they said.</li><li><strong>Open body language.</strong> Eye contact, uncrossed arms.</li><li><strong>Don''t say they''re wrong.</strong> Say "Did you know?" or "Tell me more..."</li></ul><div class="bg-amber-50 dark:bg-amber-950/30 border border-amber-300 dark:border-amber-700 rounded-lg p-4 mb-6"><p class="font-semibold text-amber-900 dark:text-amber-200">🧠 Check Yourself: Why does more time = higher close rate?</p><p class="text-sm text-muted-foreground mt-2">Time builds trust, allows thorough investigation, and gives room to build value before numbers.</p></div>', 2);

  -- Section 3
  INSERT INTO public.dealership_module_sections (module_id, title, content_type, content_html, sort_order)
  VALUES (v_module_id, 'Quick Response Tools: One-Step & Two-Step', 'text', '<h2 class="text-xl font-bold mb-4 text-primary">Your First Line of Defense</h2><p class="mb-4 leading-relaxed">Before using the full C.R.I.C. framework, try these quick techniques.</p><h3 class="text-lg font-semibold mb-3 mt-6">The One-Step (Zero-Step)</h3><p class="mb-4 leading-relaxed"><strong>Repeat the objection back</strong> as a question — and wait.</p><div class="bg-muted/50 border-l-4 border-primary p-4 rounded-r-lg mb-4"><p class="text-xs font-bold text-primary uppercase tracking-wide mb-2">CUSTOMER</p><p class="italic text-sm mb-1">"We really want to think it over."</p></div><div class="bg-muted/50 border-l-4 border-primary p-4 rounded-r-lg mb-4"><p class="text-xs font-bold text-primary uppercase tracking-wide mb-2">YOU</p><p class="italic text-sm mb-1">"Think it over?"</p><p class="italic text-sm mb-1">(Wait. Let silence work.)</p></div><h3 class="text-lg font-semibold mb-3 mt-6">The Two-Step</h3><p class="mb-4 leading-relaxed">Confirm their intention, then ask for the real reason:</p><div class="bg-muted/50 border-l-4 border-primary p-4 rounded-r-lg mb-4"><p class="text-xs font-bold text-primary uppercase tracking-wide mb-2">YOU</p><p class="italic text-sm mb-1">"Brenda, there must be a reason you''re hesitating — would you mind if I ask why?"</p></div><div class="bg-green-50 dark:bg-green-950/30 border-l-4 border-green-500 p-4 rounded-r-lg mb-4"><p class="font-medium">💡 One-Step = reflex objections. Two-Step = hidden specific concerns.</p></div><div class="bg-amber-50 dark:bg-amber-950/30 border border-amber-300 dark:border-amber-700 rounded-lg p-4 mb-6"><p class="font-semibold text-amber-900 dark:text-amber-200">🧠 Check Yourself: When would you choose One-Step over Two-Step?</p><p class="text-sm text-muted-foreground mt-2">One-Step for reflexes ("just looking"). Two-Step when you sense something specific they haven''t said.</p></div>', 3);

  -- Section 4
  INSERT INTO public.dealership_module_sections (module_id, title, content_type, content_html, sort_order)
  VALUES (v_module_id, 'The C.R.I.C. Framework', 'text', '<h2 class="text-xl font-bold mb-4 text-primary">Your Primary Objection-Handling System</h2><p class="mb-4 leading-relaxed"><strong>C.R.I.C.</strong> = <strong>Clarify, Rephrase, Isolate, Close</strong></p><div class="bg-primary/5 border border-primary/20 rounded-lg p-4 text-center mb-4"><p class="font-bold text-primary">94% of vehicles sold today have payments — budget is usually the real challenge.</p></div><div class="border-l-4 border-blue-500 bg-blue-50 dark:bg-blue-950/30 p-4 rounded-r-lg mb-4"><p class="text-2xl font-bold text-blue-600 mb-2">C — CLARIFY</p><p class="mb-2">Ask questions until the <strong>true objection</strong> surfaces.</p><div class="bg-white/60 dark:bg-black/20 rounded p-3"><p class="italic text-sm">"...so it sounds like it has everything you wanted — what was it you wanted to think over — was it something I said, the color, the equipment, or the price?"</p></div></div><div class="border-l-4 border-green-500 bg-green-50 dark:bg-green-950/30 p-4 rounded-r-lg mb-4"><p class="text-2xl font-bold text-green-600 mb-2">R — REPHRASE</p><p class="mb-2">Rephrase to Budget, Decision, or Deal. Relate personally. Tie down with "Yes."</p><div class="bg-white/60 dark:bg-black/20 rounded p-3 mb-2"><p class="italic text-sm"><strong>Budget:</strong> "Are you talking about the price like writing a check, or payments? Sounds like you''re like me — on a monthly budget, am I right?"</p></div><div class="bg-white/60 dark:bg-black/20 rounded p-3 mb-2"><p class="italic text-sm"><strong>Decision:</strong> "Sounds like you want to make sure you make a good decision — is that right?"</p></div><div class="bg-white/60 dark:bg-black/20 rounded p-3"><p class="italic text-sm"><strong>Deal:</strong> "Sounds like you want to make sure you get a good deal — is that right?"</p></div></div><div class="border-l-4 border-purple-500 bg-purple-50 dark:bg-purple-950/30 p-4 rounded-r-lg mb-4"><p class="text-2xl font-bold text-purple-600 mb-2">I — ISOLATE</p><p class="mb-2">Use <strong>"other than"</strong> to catch hidden objections.</p><div class="bg-white/60 dark:bg-black/20 rounded p-3"><p class="italic text-sm">"Other than fitting this into your budget, is there any other reason we couldn''t wrap this up right now?"</p></div></div><div class="border-l-4 border-orange-500 bg-orange-50 dark:bg-orange-950/30 p-4 rounded-r-lg mb-4"><p class="text-2xl font-bold text-orange-600 mb-2">C — CLOSE</p><p class="mb-2">Either/or on <strong>registration, refreshments, or accessories</strong>.</p><div class="bg-white/60 dark:bg-black/20 rounded p-3"><p class="italic text-sm">"Great — would you like coffee or something cold while we wrap this up?"</p></div></div><div class="bg-amber-50 dark:bg-amber-950/30 border border-amber-300 dark:border-amber-700 rounded-lg p-4 mb-6"><p class="font-semibold text-amber-900 dark:text-amber-200">🧠 Check Yourself: What does the ''I'' stand for, and why is it the most skipped step?</p><p class="text-sm text-muted-foreground mt-2">Isolate. Most skip straight to closing — but if a second objection is hiding, the close fails.</p></div>', 4);

  -- Section 5
  INSERT INTO public.dealership_module_sections (module_id, title, content_type, content_html, sort_order)
  VALUES (v_module_id, 'Putting It All Together — Full Scenario', 'text', '<h2 class="text-xl font-bold mb-4 text-primary">C.R.I.C. in Action</h2><div class="bg-purple-50 dark:bg-purple-950/30 border border-purple-200 dark:border-purple-800 rounded-lg p-4 mb-4"><p class="font-bold text-purple-800 dark:text-purple-200 mb-2">🎯 The Situation</p><p>Great demo is done. Customer loved the car. You''ve done Strive for 5. Now they hit you with this:</p></div><div class="bg-muted/50 border-l-4 border-primary p-4 rounded-r-lg mb-4"><p class="text-xs font-bold text-primary uppercase tracking-wide mb-2">CUSTOMER</p><p class="italic text-sm">"I''m just not sure this is the right vehicle for us."</p></div><p class="text-xs font-bold text-blue-600 uppercase tracking-wide mt-6 mb-2">STEP 1: CLARIFY</p><div class="bg-muted/50 border-l-4 border-blue-500 p-4 rounded-r-lg mb-2"><p class="text-xs font-bold text-blue-600 uppercase tracking-wide mb-2">YOU</p><p class="italic text-sm">"So if I understand correctly — if you thought everything was right, you''d take the car home now?"</p></div><div class="bg-muted/50 border-l-4 border-primary p-4 rounded-r-lg mb-2"><p class="text-xs font-bold uppercase tracking-wide mb-2">CUSTOMER</p><p class="italic text-sm">"Most likely, yes."</p></div><div class="bg-muted/50 border-l-4 border-blue-500 p-4 rounded-r-lg mb-2"><p class="text-xs font-bold text-blue-600 uppercase tracking-wide mb-2">YOU</p><p class="italic text-sm">"Something isn''t right then — do you mind if I ask what?"</p></div><div class="bg-muted/50 border-l-4 border-primary p-4 rounded-r-lg mb-4"><p class="text-xs font-bold uppercase tracking-wide mb-2">CUSTOMER</p><p class="italic text-sm">"We like the car but it sure seems expensive."</p></div><p class="text-xs font-bold text-green-600 uppercase tracking-wide mt-6 mb-2">STEP 2: REPHRASE TO BUDGET</p><div class="bg-muted/50 border-l-4 border-green-500 p-4 rounded-r-lg mb-2"><p class="text-xs font-bold text-green-600 uppercase tracking-wide mb-2">YOU</p><p class="italic text-sm">"When you say expensive — are you talking about the price like writing a check, or payments? Sounds like you''re like me and everybody else — on a monthly budget, am I right?"</p></div><div class="bg-muted/50 border-l-4 border-primary p-4 rounded-r-lg mb-4"><p class="text-xs font-bold uppercase tracking-wide mb-2">CUSTOMER</p><p class="italic text-sm">"Yeah, if you can fit it in our budget."</p></div><p class="text-xs font-bold text-purple-600 uppercase tracking-wide mt-6 mb-2">STEP 3: ISOLATE</p><div class="bg-muted/50 border-l-4 border-purple-500 p-4 rounded-r-lg mb-2"><p class="text-xs font-bold text-purple-600 uppercase tracking-wide mb-2">YOU</p><p class="italic text-sm">"So other than working the figures to fit your budget, is there any other reason we couldn''t wrap this up right now?"</p></div><div class="bg-muted/50 border-l-4 border-primary p-4 rounded-r-lg mb-4"><p class="text-xs font-bold uppercase tracking-wide mb-2">CUSTOMER</p><p class="italic text-sm">"No, that''s about it — but only if it fits."</p></div><p class="text-xs font-bold text-orange-600 uppercase tracking-wide mt-6 mb-2">STEP 4: CLOSE</p><div class="bg-muted/50 border-l-4 border-orange-500 p-4 rounded-r-lg mb-4"><p class="text-xs font-bold text-orange-600 uppercase tracking-wide mb-2">YOU</p><p class="italic text-sm">"Great — come on in. Would you like coffee or something cold while we wrap this up?"</p></div><div class="bg-green-50 dark:bg-green-950/30 border-l-4 border-green-500 p-4 rounded-r-lg mb-4"><p class="font-medium">💡 The initial objection was about the vehicle. The REAL objection was budget. Clarifying found the truth. Rephrasing made it workable. Isolating confirmed nothing was hiding. The close was easy because the work was already done.</p></div>', 5);

  -- Section 6
  INSERT INTO public.dealership_module_sections (module_id, title, content_type, content_html, sort_order)
  VALUES (v_module_id, 'Your Action Plan', 'text', '<h2 class="text-xl font-bold mb-4 text-primary">What To Do This Week</h2><div class="space-y-4 mb-6"><div class="flex gap-3 items-start bg-muted/30 rounded-lg p-4"><span class="bg-primary text-primary-foreground rounded-full w-8 h-8 flex items-center justify-center font-bold text-sm shrink-0">1</span><div><p class="font-semibold">Practice C.R.I.C. with a partner today</p><p class="text-sm text-muted-foreground">All three types: budget, decision, deal. Switch roles. 10 rounds.</p></div></div><div class="flex gap-3 items-start bg-muted/30 rounded-lg p-4"><span class="bg-primary text-primary-foreground rounded-full w-8 h-8 flex items-center justify-center font-bold text-sm shrink-0">2</span><div><p class="font-semibold">Track every objection this week</p><p class="text-sm text-muted-foreground">What they said, which category (B/D/D), how you handled it, outcome.</p></div></div><div class="flex gap-3 items-start bg-muted/30 rounded-lg p-4"><span class="bg-primary text-primary-foreground rounded-full w-8 h-8 flex items-center justify-center font-bold text-sm shrink-0">3</span><div><p class="font-semibold">Use the One-Step at least 3 times</p><p class="text-sm text-muted-foreground">Repeat reflex objections back. See what silence reveals.</p></div></div><div class="flex gap-3 items-start bg-muted/30 rounded-lg p-4"><span class="bg-primary text-primary-foreground rounded-full w-8 h-8 flex items-center justify-center font-bold text-sm shrink-0">4</span><div><p class="font-semibold">Debrief with your manager after every deal with objections</p><p class="text-sm text-muted-foreground">"What would you have done differently?" This is how you level up.</p></div></div></div><div class="bg-primary/5 border border-primary/20 rounded-lg p-4 text-center mb-4"><p class="font-bold text-primary text-lg">80% of sales are made after the 5th close attempt. Most salespeople only ask once. Be the exception.</p></div>', 6);

  -- Quiz Questions (10)
  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'What are the three categories that ALL objections fall into?', '[{"text": "Price, Trade, Payment", "correct": false}, {"text": "Budget, Decision, Deal", "correct": true}, {"text": "Time, Money, Value", "correct": false}, {"text": "Fear, Doubt, Competition", "correct": false}]', 'Every objection = Budget, Decision, or Deal.', 1);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'A customer says ''We want to shop around.'' What category?', '[{"text": "Budget", "correct": false}, {"text": "Decision", "correct": false}, {"text": "Deal", "correct": true}, {"text": "None of the above", "correct": false}]', 'Shopping around = Deal objection.', 2);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'What does C.R.I.C. stand for?', '[{"text": "Close, Repeat, Investigate, Confirm", "correct": false}, {"text": "Clarify, Rephrase, Isolate, Close", "correct": true}, {"text": "Connect, Rapport, Inquire, Commit", "correct": false}, {"text": "Clarify, Redirect, Inform, Close", "correct": false}]', 'Clarify, Rephrase, Isolate, Close.', 3);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'What close rate at 60 minutes or less?', '[{"text": "57%", "correct": false}, {"text": "31%", "correct": false}, {"text": "6%", "correct": true}, {"text": "22%", "correct": false}]', '6% — compare to 57% at 100+ minutes.', 4);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'In the One-Step, what do you do after repeating the objection?', '[{"text": "Present a counter-argument", "correct": false}, {"text": "Ask an either/or question", "correct": false}, {"text": "Wait in silence", "correct": true}, {"text": "Call your manager", "correct": false}]', 'Silence is powerful. The customer almost always elaborates.', 5);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'What phrase relates personally during REPHRASE?', '[{"text": "''Trust me on this...''", "correct": false}, {"text": "''You''re like me and everybody else...''", "correct": true}, {"text": "''Let me be honest...''", "correct": false}, {"text": "''Here''s what I''d do...''", "correct": false}]', 'Normalizes their concern and builds connection.', 6);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'What key phrase does ISOLATE use?', '[{"text": "''Is that final?''", "correct": false}, {"text": "''What else is bothering you?''", "correct": false}, {"text": "''Other than...''", "correct": true}, {"text": "''Let me ask you this...''", "correct": false}]', '''Other than...'' catches hidden objections.', 7);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, '''It''s too much money'' — rephrase to what?', '[{"text": "Deal", "correct": false}, {"text": "Decision", "correct": false}, {"text": "Budget — price or payments?", "correct": true}, {"text": "Just lower the price", "correct": false}]', 'Shift from fixed price to flexible monthly budget.', 8);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'Why is ''budget'' easier than ''price'' to work with?', '[{"text": "Sounds less intimidating", "correct": false}, {"text": "Monthly payments are more flexible", "correct": true}, {"text": "Makes it seem cheaper", "correct": false}, {"text": "No real difference", "correct": false}]', 'Payments can be adjusted through term, down payment, trade — multiple levers.', 9);

  INSERT INTO public.dealership_quiz_questions (module_id, question, options, explanation, sort_order)
  VALUES (v_module_id, 'After C.R.I.C., what type of closing question?', '[{"text": "Open-ended about feelings", "correct": false}, {"text": "Yes/no about signing", "correct": false}, {"text": "Either/or on registration, refreshments, or accessories", "correct": true}, {"text": "About trade-in value", "correct": false}]', 'Either/or assumes the sale without asking ''do you want to buy?''', 10);

END $$;